assignments.value:
={{
"You are Study Aura, an educational mind map generator. Create a mind map for the topic: " + ($json.body.topic || "General Study") + ". Difficulty: " + ($json.body.difficulty || "easy") + ". Create exactly " + ($json.body.branchCount || 4) + " branches.\n\n" +
"Selected source context:\n" +
(
  Array.isArray($json.body.selectedSources) && $json.body.selectedSources.length > 0
    ? $json.body.selectedSources.map((source, index) => {
        return (index + 1) + ". " + (source.title || "Untitled Source") + " [" + (source.type || "source") + "]\n" +
          "Summary or content: " + (source.summary || source.value || "No summary provided.");
      }).join("\n\n")
    : "No selected sources were provided. Use the topic only."
) +
"\n\nReturn ONLY valid JSON. No markdown. No code fences.\n" +
"Required JSON format: {\"title\": string, \"center\": string, \"description\": string, \"branches\": [{\"title\": string, \"summary\": string, \"keywords\": string[]}]}.\n" +
"Rules:\n" +
"- Each branch must have 3 to 5 short keywords.\n" +
"- Summaries should be short and student-friendly.\n" +
"- Prioritize selected source context when available.\n" +
"- Do not include markdown, comments, or text outside JSON."
}}

parameters.jsCode:
const raw = $json.output ?? "";

const cleaned = String(raw)
  .replace(/```json/g, "")
  .replace(/```/g, "")
  .trim();

let mindMap;
let fallback = false;

try {
  mindMap = JSON.parse(cleaned);

  if (!mindMap.title || !mindMap.center || !Array.isArray(mindMap.branches)) {
    throw new Error("Invalid mind map format");
  }
} catch (error) {
  fallback = true;
  mindMap = {
    title: "Study Aura Mind Map",
    center: "Main Topic",
    description: "A quick fallback concept map for organizing a study topic.",
    branches: [
      {
        title: "Core Idea",
        summary: "The main concept you should understand first.",
        keywords: ["main point", "definition", "overview"]
      },
      {
        title: "Supporting Details",
        summary: "Important facts or examples that explain the topic more clearly.",
        keywords: ["examples", "details", "evidence"]
      }
    ]
  };
}

const branches = Array.isArray(mindMap.branches)
  ? mindMap.branches.map((branch) => {
      const keywords = Array.isArray(branch.keywords)
        ? branch.keywords.map((keyword) => String(keyword)).slice(0, 5)
        : ["study", "review", "concept"];

      while (keywords.length < 3) {
        keywords.push("key idea");
      }

      return {
        title: String(branch.title || "Untitled Branch"),
        summary: String(branch.summary || "Review this concept."),
        keywords
      };
    })
  : [];

return [
  {
    json: {
      mindMap: {
        title: String(mindMap.title || "Study Aura Mind Map"),
        center: String(mindMap.center || "Main Topic"),
        description: String(mindMap.description || "Generated concept map."),
        branches
      },
      fallback,
      provider: $json.provider || "gemini"
    }
  }
];

